const express = require('express');
const rateLimiterMiddleware = require('express-rate-limit');
const app = express();
const limiter = rateLimiterMiddleware({
  windowMs: 60 * 1000,
  max: 10
});
app.use(limiter);
app.get('/users', (req, res) => {
  res.json({ message: 'Hello, users!' });
});
app.get('/products', (req, res) => {
  res.json({ message: 'Hello, products!' });
});

